def analyze_scores(scores):
    if not scores:
        return {'average_score': 0 'highest_score': 0 'lowest_score': 0 'passed': 0 'failed': 0}
    average_score = sum(scores) / len(scores)
    highest_score = max(scores)
    lowest_score = min(scores)
    passed = sum(1 for s in scores if s >= 60)
    failed = len(scores) - passed
    return {'average_score': average_score 'highest_score': highest_score 'lowest_score': lowest_score 'passed': passed 'failed': failed}
